import React, { useState } from 'react'
import { useQuery, useAction, getTeamTasks, createTask } from 'wasp/client/operations'
import { useParams, Link } from 'wasp/client/router'

export const TeamPage = () => {
  const { id } = useParams()
  const teamId = id ? parseInt(id) : undefined
  const { data: tasks, isLoading, error } = useQuery(getTeamTasks, { teamId: teamId as number }, { enabled: !!teamId })
  const createTaskAction = useAction(createTask)
  const [description, setDescription] = useState('')

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!teamId) return
    try {
      await createTaskAction({ description, teamId })
      setDescription('')
    } catch (err: any) {
      window.alert('Error creating task: ' + err.message)
    }
  }

  if (isLoading) return 'Loading...'
  if (error) return (
    <div>
      <p>Error: {error.message}</p>
      <Link to="/">Back to Dashboard</Link>
    </div>
  )

  return (
    <div style={{ padding: '20px' }}>
      <Link to="/">← Back to Dashboard</Link>
      <h1>Team Tasks</h1>
      {tasks?.length === 0 ? (
        <p>No tasks yet.</p>
      ) : (
        <ul>
          {tasks?.map((task) => (
            <li key={task.id}>
              {task.description} {task.isDone ? '✅' : '⏳'}
            </li>
